class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def plus_one(head: ListNode) -> ListNode:
    """
    Given a non-negative integer represented as a linked list, add one to the number.
    The digits are stored such that the most significant digit is at the head of the list.
    """

    def reverse_list(head):
        prev = None
        curr = head
        while curr:
            next_node = curr.next
            curr.next = prev
            prev = curr
            curr = next_node
        return prev

    def list_to_number(head):
        num = 0
        while head:
            num = num * 10 + head.val
            head = head.next
        return num

    def number_to_list(num):
        if num == 0:
            return ListNode(0)

        dummy_head = ListNode(0)
        curr = dummy_head

        digits = []
        while num > 0:
            digits.append(num % 10)
            num //= 10

        for digit in reversed(digits):
            curr.next = ListNode(digit)
            curr = curr.next

        return dummy_head.next


    num = list_to_number(head)
    num += 1

    return number_to_list(num)
